import { apiClient } from './index';

// Radar / 透地雷達 API
export async function apiGetRadarItems(): Promise<any> {
  const response = await apiClient.post('/api/Radar/GetRadarItems', {});
  return response.data;
}

export interface RadarQuery {
  checkYear?: number | string;
  riverName?: string;
  targetName?: string;
  keyword?: string;
}

export async function apiGetRadarDatas(query: RadarQuery): Promise<any[]> {
  const params = new URLSearchParams();
  if (query.checkYear !== undefined && query.checkYear !== '') params.set('checkYear', String(query.checkYear));
  if (query.riverName) params.set('riverName', query.riverName);
  if (query.targetName) params.set('targetName', query.targetName);
  if (query.keyword) params.set('keyword', query.keyword);

  const response = await apiClient.post(`/api/Radar/GetRadarDatas?${params.toString()}`, {});
  return response.data;
}

export async function apiGetRadarImage(radarId: number | string, imageId: string): Promise<Blob> {
  const response = await apiClient.get(`/api/Radar/GetRadarImage?radarId=${radarId}&imageId=${encodeURIComponent(imageId)}`, { responseType: 'blob' });
  return response.data as Blob;
}

export async function apiGetRadarExcel(radarId: number | string): Promise<Blob> {
  const response = await apiClient.get(`/api/Radar/GetRadarExcel?radarId=${radarId}`, { responseType: 'blob' });
  return response.data as Blob;
}
