<template>
  <div class="radar-page">
    <div class="toolbar">
      <div class="filters">
        <el-select v-model="filters.checkYear" placeholder="年度" class="w120" @change="onYearChange">
          <el-option v-for="y in yearOptions" :key="y.value" :label="y.label" :value="y.value" />
        </el-select>
        <el-select v-model="filters.riverName" placeholder="河系" class="w160" @change="onRiverChange">
          <el-option v-for="r in riverOptions" :key="r.value" :label="r.label" :value="r.value" />
        </el-select>
        <el-select v-model="filters.targetName" placeholder="水利建造物" class="w160" @change="loadList">
          <el-option v-for="t in targetOptions" :key="t.value" :label="t.label" :value="t.value" />
        </el-select>
        <el-input v-model="filters.keyword" placeholder="關鍵字" class="w200" />
        <el-button type="primary" @click="loadList">搜尋</el-button>
        <el-button @click="downloadList">下載清單</el-button>
        <el-button @click="downloadAll">下載整批</el-button>
      </div>
      <div class="note">透地雷達成果查詢</div>
    </div>

    <div class="content">
      <div class="map-panel">
        <!-- 先使用既有 GoogleMap 圖台元件，加入透地雷達測線 -->
        <GoogleMapMain :radarPath="radarPath" />
      </div>
      <div class="list-panel">
        <el-table :data="list" height="100%" @row-click="onRowClick">
          <el-table-column prop="radarId" label="ID" width="70" />
          <el-table-column prop="targetName" label="水利建造物" />
          <el-table-column prop="result" label="成果" />
          <el-table-column prop="title" label="Excel" />
        </el-table>
      </div>
    </div>

    <el-dialog v-model="showImage" width="70%" title="透地雷達成果" @close="resetZoom">
      <div class="image-toolbar">
        <el-select v-model="selectedImageId" placeholder="選擇測線" class="w200" @change="loadImage">
          <el-option v-for="img in imageOptions" :key="img.imageId" :label="img.imageName" :value="img.imageId" />
        </el-select>
        <el-button @click="zoomIn">+</el-button>
        <el-button @click="zoomOut">-</el-button>
        <el-button @click="downloadImage" type="primary">下載圖片</el-button>
      </div>
      <div class="image-wrapper">
        <img v-if="imageUrl" :src="imageUrl" alt="radar" :style="{ transform: `scale(${zoom})` }" />
      </div>
    </el-dialog>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, ref } from 'vue';
import GoogleMapMain from '@/components/CCTV/GoogleMapMain.vue';
import { apiGetRadarItems, apiGetRadarDatas, apiGetRadarExcel, apiGetRadarImage, RadarQuery } from '@/resource/radar';

const filters = ref<RadarQuery>({ checkYear: '', riverName: '', targetName: '', keyword: '' });
const list = ref<any[]>([]);

const yearOptions = ref<Array<{ label: string; value: number | string; lstRiver?: any[] }>>([]);
const riverOptions = ref<Array<{ label: string; value: string; lstTarget?: any[] }>>([]);
const targetOptions = ref<Array<{ label: string; value: string }>>([]);

const showImage = ref(false);
const imageUrl = ref('');
const zoom = ref(1);
const selectedRow = ref<any>(null);
const selectedImageId = ref<string>('');
const imageOptions = ref<any[]>([]);
const radarPath = computed(() => selectedRow.value?.lstGps || []);

async function loadItems() {
  const data = await apiGetRadarItems();
  // data is an array of years
  yearOptions.value = (data || []).map((y: any) => ({
    label: y.checkYearName,
    value: y.checkYearValue,
    lstRiver: y.lstRiver || []
  }));
  yearOptions.value.unshift({ label: '全部', value: 0, lstRiver: [{ riverName: '全部', riverValue: '0', lstTarget: [{ targetName: '全部', targetValue: '0' }] }] });
  onYearChange(filters.value.checkYear || yearOptions.value?.[0]?.value);
}

function onYearChange(val: any) {
  const year = yearOptions.value.find(y => y.value === val) || yearOptions.value?.[0];
  if (!year) return;
  filters.value.checkYear = year.value;
  riverOptions.value = (year.lstRiver || []).map((r: any) => ({
    label: r.riverName,
    value: r.riverValue,
    lstTarget: r.lstTarget || []
  }));
  onRiverChange(riverOptions.value?.[0]?.value);
  loadList();
}

function onRiverChange(val: any) {
  const river = riverOptions.value.find(r => r.value === val) || riverOptions.value?.[0];
  if (!river) return;
  filters.value.riverName = river.value;
  targetOptions.value = (river.lstTarget || []).map((t: any) => ({
    label: t.targetName,
    value: t.targetValue
  }));
  filters.value.targetName = targetOptions.value?.[0]?.value || '';
  loadList();
}

async function loadList() {
  list.value = await apiGetRadarDatas(filters.value);
}

async function onRowClick(row: any) {
  if (!row) return;
  selectedRow.value = row;
  const imgs = row.lstImage || [];
  const seen = new Set();
  imageOptions.value = imgs.filter((i: any) => {
    if (!i?.imageId || seen.has(i.imageId)) return false;
    seen.add(i.imageId);
    return true;
  });
  selectedImageId.value = imageOptions.value?.[0]?.imageId || '';
  await loadImage();
  showImage.value = true;
}

async function loadImage() {
  if (!selectedRow.value || !selectedImageId.value) return;
  const blob = await apiGetRadarImage(selectedRow.value.radarId, selectedImageId.value);
  imageUrl.value = URL.createObjectURL(blob);
}

function zoomIn() { zoom.value = Math.min(3, zoom.value + 0.2); }
function zoomOut() { zoom.value = Math.max(0.5, zoom.value - 0.2); }
function resetZoom() { zoom.value = 1; }

async function downloadImage() {
  if (!selectedRow.value || !selectedImageId.value) return;
  const blob = await apiGetRadarImage(selectedRow.value.radarId, selectedImageId.value);
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${selectedImageId.value}.jpg`;
  a.click();
  URL.revokeObjectURL(url);
}

async function downloadList() {
  if (selectedRow.value?.radarId) {
    const blob = await apiGetRadarExcel(selectedRow.value.radarId);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = selectedRow.value.title || 'radar.xlsx';
    a.click();
    URL.revokeObjectURL(url);
  } else {
    alert('請先選擇一筆成果');
  }
}

async function downloadAll() {
  // 預留：需後端支援整批下載 API
  alert('整批下載需後端提供批次 API');
}

onMounted(async () => {
  await loadItems();
  await loadList();
});
</script>

<style scoped>
.radar-page { display: flex; flex-direction: column; height: calc(100vh - 100px); gap: 12px; }
.toolbar { display: flex; align-items: center; justify-content: space-between; padding: 8px 12px; background: #f7f7f7; border-radius: 8px; }
.filters { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; }
.w120 { width: 120px; }
.w160 { width: 160px; }
.w200 { width: 200px; }
.content { flex: 1; display: grid; grid-template-columns: 2fr 1fr; gap: 12px; }
.map-panel { background: #fff; border-radius: 8px; overflow: hidden; }
.list-panel { background: #fff; border-radius: 8px; overflow: hidden; padding: 8px; }
.image-toolbar { display: flex; gap: 8px; align-items: center; margin-bottom: 8px; }
.image-wrapper { display: flex; justify-content: center; align-items: center; overflow: auto; }
.image-wrapper img { max-width: 100%; max-height: 70vh; object-fit: contain; transition: transform 0.1s ease; }
</style>
